export interface IUserRepository {
  findById(id: string): Promise<User | null>;
  findByEmail(email: string): Promise<User | null>;
  findAll(params: FindAllParams): Promise<{ users: User[]; total: number }>;
  create(data: CreateUserData): Promise<User>;
  update(id: string, data: UpdateUserData): Promise<User>;
  delete(id: string): Promise<void>;
}

export class UserRepository implements IUserRepository {
  constructor(private prisma: PrismaClient) {}

  async findAll(params: FindAllParams) {
    const { page, limit, search } = params;
    const skip = (page - 1) * limit;
    const where = search
      ? { OR: [
          { name: { contains: search, mode: 'insensitive' as const } },
          { email: { contains: search, mode: 'insensitive' as const } },
        ]}
      : {};
    const [users, total] = await Promise.all([
      this.prisma.user.findMany({ where, skip, take: limit, orderBy: { createdAt: 'desc' } }),
      this.prisma.user.count({ where }),
    ]);
    return { users, total };
  }
}

export class UserService implements IUserService {
  constructor(private userRepository: IUserRepository) {}

  async createUser(data: CreateUserDto): Promise<User> {
    const existing = await this.userRepository.findByEmail(data.email);
    if (existing) throw new ConflictError('User with this email already exists');

    const hashedPassword = await hashPassword(data.password);
    return this.userRepository.create({
      email: data.email,
      name: data.name,
      hashedPassword,
    });
  }

  async updateUser(id: string, data: UpdateUserDto): Promise<User> {
    await this.getUser(id); // throws NotFoundError if missing
    if (data.email) {
      const existing = await this.userRepository.findByEmail(data.email);
      if (existing && existing.id !== id) throw new ConflictError('Email already in use');
    }
    return this.userRepository.update(id, data);
  }
}

export class UserController {
  constructor(private userService: IUserService) {}

  createUser = async (req: Request, res: Response, next: NextFunction): Promise<void> => {
    try {
      const data = CreateUserSchema.parse(req.body); // throws ZodError on invalid
      const user = await this.userService.createUser(data);
      res.status(201).json({ data: user });
    } catch (error) {
      next(error); // delegates to error handler middleware
    }
  };

  getUser = async (req: Request, res: Response, next: NextFunction): Promise<void> => {
    try {
      const { id } = req.params;
      const user = await this.userService.getUser(id);
      res.json({ data: user });
    } catch (error) {
      next(error);
    }
  };
}
